import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    available_nodes = set(unvisited_nodes) - set(truck_nodes)
    if not available_nodes:
        return None

    min_projected_distance = float('inf')
    next_node = None

    for node in available_nodes:
        projected_distance = distance_matrix[current_node][node] + distance_matrix[node][depot_node]
        if projected_distance < min_projected_distance:
            min_projected_distance = projected_distance
            next_node = node

    return next_node
